mapper.select:
SELECT k.*, COALESCE ( i.ig_username, y.username, t.unique_id ) AS account, COALESCE ( i.full_name, y.nickname, t.nickname ) AS nickname, COALESCE ( i.profile_pic_url, y.avatar_url ,t.author_avatar_url) AS avatar FROM `kol_shields` k LEFT JOIN `ig_celebrity` i ON k.celebrity_id = i.account AND k.platform_type = 0 LEFT JOIN `youtube_celebrity` y ON k.celebrity_id = y.account AND k.platform_type = 1 LEFT JOIN `tiktok_celebrity` t ON k.celebrity_id = t.author_id AND k.platform_type = 2
AND k.unique_id LIKE CONCAT('%', #{kolShieldsModel.uniqueId}, '%')
AND k.platform_type = #{kolShieldsModel.platformType}
AND k.counselor_id = #{kolShieldsModel.counselorId}
ORDER BY k.shield_time DESC
